Berikut adalah fungsi Python untuk membandingkan dua dictionary secara rekursif. Fungsi ini mendeteksi kunci yang ditambahkan, dihapus, dan nilai yang berubah (termasuk pada nested dictionary).

```python
def diff_dicts(dict1, dict2, path=""):
    """
    Recursively diff two dictionaries.

    Returns a dictionary containing:
    - 'added': keys present in dict2 but not in dict1
    - 'removed': keys present in dict1 but not in dict2
    - 'changed': keys with different values
    - 'unchanged': keys with identical values
    """
    result = {
        'added': {},
        'removed': {},
        'changed': {},
        'unchanged': {}
    }

    all_keys = set(dict1.keys()) | set(dict2.keys())

    for key in all_keys:
        current_path = f"{path}.{key}" if path else key

        if key not in dict1:
            result['added'][current_path] = dict2[key]
        elif key not in dict2:
            result['removed'][current_path] = dict1[key]
        elif isinstance(dict1[key], dict) and isinstance(dict2[key], dict):
            # Recurse into nested dictionaries
            nested_diff = diff_dicts(dict1[key], dict2[key], current_path)

            for category in ['added', 'removed', 'changed']:
                if nested_diff[category]:
                    result[category].update(nested_diff[category])

            if nested_diff['unchanged']:
                result['unchanged'].update(nested_diff['unchanged'])
        elif dict1[key] != dict2[key]:
            result['changed'][current_path] = {
                'old': dict1[key],
                'new': dict2[key]
            }
        else:
            result['unchanged'][current_path] = dict1[key]

    return result


def diff_dicts_simple(dict1, dict2, path=""):
    """
    Simplified version - only returns differences (added, removed, changed).
    More suitable for production use where you only care about changes.
    """
    result = {
        'added': {},
        'removed': {},
        'changed': {}
    }

    all_keys = set(dict1.keys()) | set(dict2.keys())

    for key in all_keys:
        current_path = f"{path}.{key}" if path else key

        if key not in dict1:
            result['added'][current_path] = dict2[key]
        elif key not in dict2:
            result['removed'][current_path] = dict1[key]
        elif isinstance(dict1[key], dict) and isinstance(dict2[key], dict):
            nested_diff = diff_dicts_simple(dict1[key], dict2[key], current_path)

            for category in ['added', 'removed', 'changed']:
                if nested_diff[category]:
                    result[category].update(nested_diff[category])
        elif dict1[key] != dict2[key]:
            result['changed'][current_path] = {
                'old': dict1[key],
                'new': dict2[key]
            }

    # Remove empty categories
    result = {k: v for k, v in result.items() if v}

    return result


# Example usage
if __name__ == "__main__":
    dict_a = {
        'user': {
            'name': 'John',
            'age': 25,
            'settings': {
                'theme': 'dark',
                'notifications': True
            }
        },
        'version': '1.0'
    }

    dict_b = {
        'user': {
            'name': 'John',
            'age': 26,
            'settings': {
                'theme': 'light',
                'language': 'en'
            }
        },
        'version': '1.1',
        'status': 'active'
    }

    diff = diff_dicts_simple(dict_a, dict_b)

    print("=== Dictionary Diff Result ===")
    for category, changes in diff.items():
        if changes:
            print(f"\n{category.upper()}:")
            for key, value in changes.items():
                if isinstance(value, dict) and 'old' in value:
                    print(f"  {key}: {value['old']} → {value['new']}")
                else:
                    print(f"  {key}: {value}")
